sub blessed_ref {
    my ($ref) = @_;
    my $reftype = ref $ref;
    return 0 unless $reftype;
    # If ref() returns something other than HASH, ARRAY, SCALAR, REF, CODE, GLOB
    # then it's a blessed reference
    return !grep { $reftype eq $_ } qw(HASH ARRAY SCALAR REF CODE GLOB);
}

