package SessionManager;

use strict;
use warnings;

sub new {
    my ($class, %opts) = @_;

    my $self = bless {
        cgi          => $opts{cgi} || CGI->new(),
        session_id   => undef,
        session_data => undef,
        is_new       => 0,
        is_modified  => 0,
    }, $class;

    return $self;
}

# Initialize or resume a session
sub init {
    my ($self) = @_;

    # Try to get session ID from cookie
    my %cookies = CGI::Cookie->fetch();
    my $session_id;

    if (exists $cookies{'session_id'}) {
        $session_id = $cookies{'session_id'}->value();
    }

    # Attempt to load existing session
    if (defined $session_id && main::validate_session_id($session_id)) {
        my $filepath = main::get_session_filepath($session_id);

        if (defined $filepath && -f $filepath) {
            my $data = eval { main::safe_retrieve($filepath) };

            if (defined $data) {
                # Check session timeout
                if (time() - $data->{_last_access} > $SESSION_TIMEOUT) {
                    # Session expired - destroy and create new
                    $self->_destroy_session_file($filepath);
                    $self->_create_new_session();
                } else {
                    # Valid session - resume
                    $self->{session_id} = $session_id;
                    $self->{session_data} = $data;
                    $self->{session_data}{_last_access} = time();
                    $self->{is_modified} = 1;
                }
            } else {
                # Invalid/corrupted session data - create new
                warn "Session data invalid or corrupted, creating new session";
                $self->_destroy_session_file($filepath);
                $self->_create_new_session();
            }
        } else {
            # Session file doesn't exist - create new
            $self->_create_new_session();
        }
    } else {
        # No valid session ID - create new
        $self->_create_new_session();
    }

    return $self;
}

sub _create_new_session {
    my ($self) = @_;

    $self->{session_id} = main::generate_session_id();
    $self->{session_data} = {
        _session_id  => $self->{session_id},
        _created     => time(),
        _last_access => time(),
    };
    $self->{is_new} = 1;
    $self->{is_modified} = 1;
}

sub _destroy_session_file {
    my ($self, $filepath) = @_;

    if (defined $filepath && -f $filepath) {
        unlink($filepath) or warn "Cannot remove expired session file: $!";
    }
}

# Get a session value
sub get {
    my ($self, $key) = @_;

    return undef unless defined $self->{session_data};

    # Prevent access to internal fields
    if ($key =~ /\A_/) {
        warn "Cannot directly access internal session field: $key";
        return undef;
    }

    return $self->{session_data}{$key};
}

# Set a session value
sub set {
    my ($self, $key, $value) = @_;

    return 0 unless defined $self->{session_data};

    # Prevent modification of internal fields
    if ($key =~ /\A_/) {
        warn "Cannot directly modify internal session field: $key";
        return 0;
    }

    # Only allow simple scalar values, arrayrefs of scalars, or hashrefs of scalars
    # to prevent storing objects that could be exploited during deserialization
    unless (_is_safe_value($value)) {
        warn "Attempted to store unsafe value type in session";
        return 0;
    }

    $self->{session_data}{$key} = $value;
    $self->{is_modified} = 1;

    return 1;
}

sub _is_safe_value {
    my ($value) = @_;

    return 1 unless defined $value;
    return 1 unless ref $value;

    if (main::blessed_ref($value)) {
        return 0; # No blessed objects
    }

    if (ref $value eq 'HASH') {
        for my $v (values %$value) {
            return 0 unless _is_safe_value($v);
        }
        return 1;
    }

    if (ref $value eq 'ARRAY') {
        for my $v (@$value) {
            return 0 unless _is_safe_value($v);
        }
        return 1;
    }

    if (ref $value eq 'SCALAR') {
        return 1;
    }

    # Reject CODE, GLOB, REF to CODE, etc.
    return 0;
}

# Delete a session value
sub delete {
    my ($self, $key) = @_;

    return unless defined $self->{session_data};

    if ($key =~ /\A_/) {
        warn "Cannot delete internal session field: $key";
        return;
    }

    if (exists $self->{session_data}{$key}) {
        delete $self->{session_data}{$key};
        $self->{is_modified} = 1;
    }
}

# Save session to disk
sub save {
    my ($self) = @_;

    return 1 unless $self->{is_modified};

    my $filepath = main::get_session_filepath($self->{session_id});
    return 0 unless defined $filepath;

    $self->{session_data}{_last_access} = time();

    return main::safe_store($self->{session_data}, $filepath);
}

# Get the session cookie to send to client
sub get_cookie {
    my ($self) = @_;

    my $cookie = CGI::Cookie->new(
        -name     => 'session_id',
        -value    => $self->{session_id},
        -path     => '/',
        -httponly  => 1,
        -secure   => 1,       # Only send over HTTPS
        -samesite => 'Strict',
        -expires  => '+1h',
    );

    return $cookie;
}

# Destroy the current session
sub destroy {
    my ($self) = @_;

    if (defined $self->{session_id}) {
        my $filepath = main::get_session_filepath($self->{session_id});
        $self->_destroy_session_file($filepath) if defined $filepath;
    }

    $self->{session_id} = undef;
    $self->{session_data} = undef;
    $self->{is_modified} = 0;
}

# Get session ID
sub session_id {
    my ($self) = @_;
    return $self->{session_id};
}

# Check if this is a new session
sub is_new {
    my ($self) = @_;
    return $self->{is_new};
}

# Clean up expired sessions (call periodically)
sub cleanup_expired_sessions {
    my ($class_or_self) = @_;

    opendir(my $dh, $SESSION_DIR) or do {
        warn "Cannot open session directory for cleanup: $!";
        return;
    };

    my $now = time();
    my $cleaned = 0;

    while (my $entry = readdir($dh)) {
        next unless $entry =~ /\Asess_[a-f0-9]{64}\z/;

        my $filepath = File::Spec->catfile($SESSION_DIR, $entry);

        # Check modification time
        my @stat = stat($filepath);
        next unless @stat;

        if ($now - $stat[9] > $SESSION_TIMEOUT * 2) {
            # File is old enough to clean up
            if (unlink($filepath)) {
                $cleaned++;
            }
        }
    }

    closedir($dh);
    return $cleaned;
}

